export function normalizeCityName(s: string): string {
  return s.toLowerCase().replace(/[^a-z0-9 ]/g, ' ').replace(/\s+/g, ' ').trim();
}

export function lookupCityCoord(name: string): { lat: number; lng: number } | null {
  return ISRAEL_CITIES[normalizeCityName(name)] ?? null;
}
